package embedder

import (
	"strings"
	"testing"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
)

func TestNewEmbedderMock(t *testing.T) {
	cfg := config.EmbedderConfig{
		Backend:    "mock",
		Dimensions: 768,
	}
	emb, err := NewEmbedder(cfg)
	if err != nil {
		t.Fatalf("NewEmbedder: %v", err)
	}
	if emb.Dimensions() != 768 {
		t.Errorf("dimensions = %d, want 768", emb.Dimensions())
	}
}

func TestNewEmbedderUnknown(t *testing.T) {
	cfg := config.EmbedderConfig{Backend: "unknown"}
	_, err := NewEmbedder(cfg)
	if err == nil {
		t.Fatal("expected error for unknown backend")
	}
	if !strings.Contains(err.Error(), "unknown embedder backend") {
		t.Errorf("unexpected error: %v", err)
	}
}

func TestNewEmbedderONNXNotImplemented(t *testing.T) {
	cfg := config.EmbedderConfig{Backend: "onnx"}
	_, err := NewEmbedder(cfg)
	if err == nil {
		t.Fatal("expected error for onnx backend")
	}
	if !strings.Contains(err.Error(), "not yet implemented") {
		t.Errorf("unexpected error: %v", err)
	}
}
